class RelationshipManager:
    """好感度管理器"""
    def __init__(self):
        self.affinity_data = {}
        self.llm = HelloAgentsLLM()

    def analyze_sentiment(self, player_msg, npc_reply):
        """分析对话情感，返回好感度变化值"""
        prompt = f"""分析玩家态度：
玩家：{player_msg}
NPC：{npc_reply}
请判断：
1. 友好(+5)：礼貌、热情、感谢
2. 中立(+2)：普通询问或陈述
3. 不友好(-3)：粗鲁、冷漠、批评
只返回数字。"""
        response = self.llm.think([
            {"role": "user", "content": prompt}
        ])
        return max(-3, min(5, int(response.strip())))

    def update_affinity(self, npc_id, player_name,
                        player_msg, npc_reply):
        key = f"{npc_id}_{player_name}"
        if key not in self.affinity_data:
            self.affinity_data[key] = {
                "score": 0, "level": "陌生",
                "interaction_count": 0}
        score_change = self.analyze_sentiment(
            player_msg, npc_reply)
        new_score = max(0, min(100,
            self.affinity_data[key]["score"]
            + score_change))
        level = self._get_level(new_score)
        self.affinity_data[key].update({
            "score": new_score, "level": level,
            "interaction_count":
                self.affinity_data[key]["interaction_count"] + 1})
        return self.affinity_data[key]

    def _get_level(self, score):
        if score <= 20: return "陌生"
        elif score <= 40: return "熟悉"
        elif score <= 60: return "友好"
        elif score <= 80: return "亲密"
        else: return "挚友"
